1	import { useState, useEffect } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	import { Button } from "@/components/ui/button";
5	import { Card } from "@/components/ui/card";
6	import { Badge } from "@/components/ui/badge";
7	import { motion } from "framer-motion";
8	import { Plus, MessageSquare, FileSignature, Receipt, ArrowRight, Sparkles, Users } from "lucide-react";
9	
10	const WorkspacesList = () => {
11	  const navigate = useNavigate();
12	  const [workspaces, setWorkspaces] = useState<any[]>([]);
13	  const [loading, setLoading] = useState(true);
14	  const [userId, setUserId] = useState<string | null>(null);
15	
16	  useEffect(() => { fetchWorkspaces(); }, []);
17	
18	  const fetchWorkspaces = async () => {
19	    const { data: { user } } = await supabase.auth.getUser();
20	    if (!user) return;
21	    setUserId(user.id);
22	
23	    const { data } = await supabase
24	      .from("chat_rooms")
25	      .select("*, chat_room_members(user_id, role)")
26	      .order("updated_at", { ascending: false });
27	
28	    setWorkspaces(data || []);
29	    setLoading(false);
30	  };
31	
32	  const createWorkspace = async () => {
33	    if (!userId) return;
34	    const { data, error } = await supabase
35	      .from("chat_rooms")
36	      .insert({ created_by: userId, is_group: false, name: "New Workspace" })
37	      .select()
38	      .single();
39	
40	    if (!error && data) {
41	      await supabase.from("chat_room_members").insert({ room_id: data.id, user_id: userId, role: "admin" });
42	      navigate(`/crevia-workspace/${data.id}`);
43	    }
44	  };
45	
46	  return (
47	    <div className="min-h-screen bg-background">
48	      <div className="max-w-5xl mx-auto px-4 py-8 md:px-6 md:py-12">
49	        {/* Header */}
50	        <div className="flex items-center justify-between mb-8">
51	          <div>
52	            <div className="flex items-center gap-2 mb-1">
53	              <Sparkles className="w-5 h-5 text-bronze" />
54	              <h1 className="font-vollkorn text-2xl md:text-3xl font-bold">Workspaces</h1>
55	            </div>
56	            <p className="text-muted-foreground text-sm">Your active deal rooms with clients and brands</p>
57	          </div>
58	          <Button onClick={createWorkspace} className="bg-bronze hover:bg-bronze/90 text-background gap-2">
59	            <Plus className="w-4 h-4" />
60	            New Workspace
61	          </Button>
62	        </div>
63	
64	        {/* Workspaces Grid */}
65	        {loading ? (
66	          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
67	            {[...Array(4)].map((_, i) => (
68	              <div key={i} className="h-36 bg-muted/50 rounded-2xl animate-pulse" />
69	            ))}
70	          </div>
71	        ) : workspaces.length === 0 ? (
72	          <div className="text-center py-24">
73	            <div className="w-20 h-20 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
74	              <MessageSquare className="w-10 h-10 text-bronze/50" />
75	            </div>
76	            <h3 className="font-vollkorn text-xl font-bold mb-2">No workspaces yet</h3>
77	            <p className="text-muted-foreground text-sm mb-6 max-w-sm mx-auto">
78	              Create your first workspace to start collaborating with a client or brand in a professional deal room.
79	            </p>
80	            <Button onClick={createWorkspace} className="bg-bronze hover:bg-bronze/90 text-background gap-2">
81	              <Plus className="w-4 h-4" />
82	              Create First Workspace
83	            </Button>
84	          </div>
85	        ) : (
86	          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
87	            {workspaces.map((workspace, idx) => (
88	              <motion.div
89	                key={workspace.id}
90	                initial={{ opacity: 0, y: 16 }}
91	                animate={{ opacity: 1, y: 0 }}
92	                transition={{ duration: 0.3, delay: idx * 0.05 }}
93	              >
94	                <Card
95	                  onClick={() => navigate(`/crevia-workspace/${workspace.id}`)}
96	                  className="p-5 cursor-pointer hover:border-bronze/40 hover:shadow-md transition-all group"
97	                >
98	                  <div className="flex items-start justify-between mb-4">
99	                    <div className="flex items-center gap-3">
100	                      <div className="w-10 h-10 rounded-xl bg-bronze/10 flex items-center justify-center">
101	                        <MessageSquare className="w-5 h-5 text-bronze" />
102	                      </div>
103	                      <div>
104	                        <h3 className="font-semibold text-sm">{workspace.name || "Workspace"}</h3>
105	                        <p className="text-[10px] text-muted-foreground">
106	                          {new Date(workspace.updated_at).toLocaleDateString()}
107	                        </p>
108	                      </div>
109	                    </div>
110	                    <Badge variant="outline" className="text-[10px] border-bronze/30 text-bronze">
111	                      Active
112	                    </Badge>
113	                  </div>
114	
115	                  <div className="flex items-center gap-3 mb-4">
116	                    <div className="flex items-center gap-1.5 text-muted-foreground">
117	                      <Users className="w-3.5 h-3.5" />
118	                      <span className="text-xs">{workspace.chat_room_members?.length || 1} members</span>
119	                    </div>
120	                    <div className="flex items-center gap-1.5 text-muted-foreground">
121	                      <FileSignature className="w-3.5 h-3.5" />
122	                      <span className="text-xs">Contract</span>
123	                    </div>
124	                    <div className="flex items-center gap-1.5 text-muted-foreground">
125	                      <Receipt className="w-3.5 h-3.5" />
126	                      <span className="text-xs">Invoice</span>
127	                    </div>
128	                  </div>
129	
130	                  <div className="flex items-center justify-between">
131	                    <span className="text-xs text-muted-foreground">Click to open workspace</span>
132	                    <ArrowRight className="w-4 h-4 text-bronze opacity-0 group-hover:opacity-100 transition-opacity" />
133	                  </div>
134	                </Card>
135	              </motion.div>
136	            ))}
137	          </div>
138	        )}
139	      </div>
140	    </div>
141	  );
142	};
143	
144	export default WorkspacesList;
