1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { motion, AnimatePresence } from "framer-motion";
4	import {
5	  MessageSquare,
6	  ArrowLeft,
7	  Sparkles,
8	  Loader2,
9	  MessageCircle,
10	  Users,
11	} from "lucide-react";
12	import { Button } from "@/components/ui/button";
13	import { Input } from "@/components/ui/input";
14	import {
15	  Dialog,
16	  DialogContent,
17	  DialogHeader,
18	  DialogTitle,
19	} from "@/components/ui/dialog";
20	import { toast } from "sonner";
21	import { cn } from "@/lib/utils";
22	import CreviaChat from "@/components/crevia-connect/shared/CreviaChat";
23	import WorkspaceInboxList from "./WorkspaceInboxList";
24	
25	interface SelectedRoom {
26	  id: string;
27	  name: string | null;
28	  type: "workspace" | "dm";
29	}
30	
31	interface WorkspaceMember {
32	  user_id: string;
33	  role: string;
34	  profile: {
35	    display_name: string | null;
36	    handle: string | null;
37	    avatar_url: string | null;
38	    user_type: string | null;
39	  } | null;
40	}
41	
42	const StudioWorkspacesHub = ({ initialRoomId }: { initialRoomId?: string } = {}) => {
43	  const [userId, setUserId] = useState("");
44	  const [selectedRoom, setSelectedRoom] = useState<SelectedRoom | null>(null);
45	  const [showMobileChat, setShowMobileChat] = useState(false);
46	
47	  // Workspace members for the centre pane
48	  const [workspaceMembers, setWorkspaceMembers] = useState<WorkspaceMember[]>([]);
49	  const [loadingMembers, setLoadingMembers] = useState(false);
50	
51	  // Active DM inside a workspace context
52	  const [activeDm, setActiveDm] = useState<{ roomId: string; name: string } | null>(null);
53	  const [openingDm, setOpeningDm] = useState<string | null>(null);
54	
55	  // Propose workspace dialog
56	  const [proposeDialogOpen, setProposeDialogOpen] = useState(false);
57	  const [proposeName, setProposeName] = useState("");
58	  const [proposeSending, setProposeSending] = useState(false);
59	
60	  useEffect(() => {
61	    supabase.auth.getUser().then(({ data: { user } }) => {
62	      if (user) setUserId(user.id);
63	    });
64	  }, []);
65	
66	  // Auto-select a room when navigated from a notification
67	  useEffect(() => {
68	    if (!initialRoomId || !userId) return;
69	    supabase
70	      .from("chat_rooms")
71	      .select("id, name, is_group")
72	      .eq("id", initialRoomId)
73	      .single()
74	      .then(({ data: room }) => {
75	        if (room) {
76	          handleSelectRoom(
77	            { id: room.id, name: room.name },
78	            room.is_group ? "workspace" : "dm"
79	          );
80	        }
81	      });
82	  // eslint-disable-next-line react-hooks/exhaustive-deps
83	  }, [initialRoomId, userId]);
84	
85	  const handleSelectRoom = async (
86	    room: { id: string; name: string | null },
87	    type: "workspace" | "dm"
88	  ) => {
89	    setActiveDm(null);
90	    setSelectedRoom({ id: room.id, name: room.name, type });
91	    setShowMobileChat(true);
92	
93	    if (type === "workspace") {
94	      setLoadingMembers(true);
95	      const { data: memberRows } = await supabase
96	        .from("chat_room_members")
97	        .select("user_id, role")
98	        .eq("room_id", room.id);
99	
100	      const others = (memberRows || []).filter((m: any) => m.user_id !== userId);
101	
102	      if (others.length > 0) {
103	        const otherIds = others.map((m: any) => m.user_id);
104	        const { data: profiles } = await supabase
105	          .from("profiles")
106	          .select("id, display_name, handle, avatar_url, user_type")
107	          .in("id", otherIds);
108	
109	        const profileMap = Object.fromEntries(
110	          (profiles || []).map((p: any) => [p.id, p])
111	        );
112	
113	        setWorkspaceMembers(
114	          others.map((m: any) => ({
115	            user_id: m.user_id,
116	            role: m.role,
117	            profile: profileMap[m.user_id] ?? null,
118	          }))
119	        );
120	      } else {
121	        setWorkspaceMembers([]);
122	      }
123	      setLoadingMembers(false);
124	    } else {
125	      setWorkspaceMembers([]);
126	    }
127	  };
128	
129	  const openDmWithMember = async (targetUserId: string, targetName: string) => {
130	    if (!userId) return;
131	    setOpeningDm(targetUserId);
132	
133	    const { data: myRooms } = await supabase
134	      .from("chat_room_members")
135	      .select("room_id")
136	      .eq("user_id", userId);
137	
138	    const myRoomIds = (myRooms || []).map((r: any) => r.room_id);
139	
140	    if (myRoomIds.length > 0) {
141	      const { data: shared } = await supabase
142	        .from("chat_room_members")
143	        .select("room_id, chat_rooms:room_id(is_group)")
144	        .eq("user_id", targetUserId)
145	        .in("room_id", myRoomIds);
146	
147	      const existing = (shared || []).find(
148	        (r: any) => r.chat_rooms?.is_group === false
149	      );
150	      if (existing) {
151	        setActiveDm({ roomId: existing.room_id, name: targetName });
152	        setOpeningDm(null);
153	        return;
154	      }
155	    }
156	
157	    const { data: room, error } = await supabase
158	      .from("chat_rooms")
159	      .insert({ created_by: userId, is_group: false })
160	      .select()
161	      .single();
162	
163	    if (error || !room) {
164	      toast.error("Failed to open chat");
165	      setOpeningDm(null);
166	      return;
167	    }
168	
169	    await supabase.from("chat_room_members").insert([
170	      { room_id: room.id, user_id: userId, role: "admin" },
171	      { room_id: room.id, user_id: targetUserId, role: "member" },
172	    ]);
173	
174	    setActiveDm({ roomId: room.id, name: targetName });
175	    setOpeningDm(null);
176	  };
177	
178	  const handleProposeWorkspace = async () => {
179	    if (!selectedRoom || !userId || !proposeName.trim()) return;
180	    setProposeSending(true);
181	    const { error } = await supabase.from("chat_messages").insert({
182	      room_id: selectedRoom.id,
183	      sender_id: userId,
184	      message_type: "workspace_invite",
185	      content: JSON.stringify({
186	        status: "pending",
187	        workspace_name: proposeName.trim(),
188	      }),
189	      is_encrypted: false,
190	    });
191	    setProposeSending(false);
192	    if (error) {
193	      toast.error("Failed to send workspace invite");
194	    } else {
195	      toast.success("Workspace invite sent!");
196	      setProposeDialogOpen(false);
197	      setProposeName("");
198	    }
199	  };
200	
201	  const isWorkspace = selectedRoom?.type === "workspace";
202	
203	  return (
204	    <div className="flex h-full w-full overflow-hidden bg-background">
205	      {/* ── PANE 1: Inbox List ── */}
206	      <div
207	        className={cn(
208	          "flex-shrink-0 border-r border-gray-100 dark:border-border/60",
209	          showMobileChat ? "hidden md:flex" : "flex w-full md:w-auto"
210	        )}
211	      >
212	        {userId && (
213	          <WorkspaceInboxList
214	            selectedRoomId={selectedRoom?.id ?? null}
215	            onSelectRoom={handleSelectRoom}
216	            userId={userId}
217	          />
218	        )}
219	      </div>
220	
221	      {/* ── PANE 2: Centre ── */}
222	      <div
223	        className={cn(
224	          "flex flex-col min-h-0 min-w-0 overflow-hidden flex-1",
225	          showMobileChat ? "flex" : "hidden md:flex"
226	        )}
227	      >
228	        {/* Mobile back button */}
229	        <div className="md:hidden flex-shrink-0 px-3 py-2 border-b border-gray-100 dark:border-border/50">
230	          <button
231	            onClick={() => {
232	              setShowMobileChat(false);
233	              setActiveDm(null);
234	            }}
235	            className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors"
236	          >
237	            <ArrowLeft className="w-4 h-4" />
238	            All messages
239	          </button>
240	        </div>
241	
242	        {/* DM toolbar — Propose Workspace */}
243	        <AnimatePresence>
244	          {selectedRoom?.type === "dm" && !activeDm && (
245	            <motion.div
246	              key="dm-toolbar"
247	              initial={{ opacity: 0, height: 0 }}
248	              animate={{ opacity: 1, height: "auto" }}
249	              exit={{ opacity: 0, height: 0 }}
250	              transition={{ duration: 0.18 }}
251	              className="flex-shrink-0 border-b border-gray-100 dark:border-border/50 px-4 py-2 flex items-center gap-2 overflow-hidden"
252	            >
253	              <Button
254	                size="sm"
255	                variant="outline"
256	                onClick={() => {
257	                  setProposeName("");
258	                  setProposeDialogOpen(true);
259	                }}
260	                className="h-7 text-xs gap-1.5 border-bronze/30 text-bronze hover:bg-primary hover:text-primary-foreground font-medium"
261	              >
262	                <Sparkles className="w-3 h-3" />
263	                Propose Workspace
264	              </Button>
265	              <span className="text-[10px] text-muted-foreground/50">
266	                Invite this person to a deal room
267	              </span>
268	            </motion.div>
269	          )}
270	        </AnimatePresence>
271	
272	        {/* Centre content */}
273	        <div className="flex-1 min-h-0 overflow-hidden">
274	          <AnimatePresence mode="wait">
275	            {selectedRoom?.type === "dm" || activeDm ? (
276	              <motion.div
277	                key={activeDm?.roomId ?? selectedRoom?.id}
278	                initial={{ opacity: 0 }}
279	                animate={{ opacity: 1 }}
280	                exit={{ opacity: 0 }}
281	                transition={{ duration: 0.15 }}
282	                className="h-full flex flex-col"
283	              >
284	                {activeDm && (
285	                  <div className="flex-shrink-0 px-4 py-2 border-b border-gray-100 dark:border-border/50 flex items-center gap-2 bg-card/30">
286	                    <button
287	                      onClick={() => setActiveDm(null)}
288	                      className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors"
289	                    >
290	                      <ArrowLeft className="w-3.5 h-3.5" />
291	                      Back to workspace
292	                    </button>
293	                    <span className="text-[10px] text-muted-foreground/40">·</span>
294	                    <span className="text-xs font-medium text-foreground/70">
295	                      {activeDm.name}
296	                    </span>
297	                  </div>
298	                )}
299	                <div className="flex-1 min-h-0">
300	                  <CreviaChat
301	                    externalRoomId={activeDm?.roomId ?? selectedRoom!.id}
302	                    hideRoomList
303	                    onBack={() =>
304	                      activeDm ? setActiveDm(null) : setShowMobileChat(false)
305	                    }
306	                  />
307	                </div>
308	              </motion.div>
309	            ) : isWorkspace && selectedRoom ? (
310	              /* Workspace member list */
311	              <motion.div
312	                key={`ws-${selectedRoom.id}`}
313	                initial={{ opacity: 0 }}
314	                animate={{ opacity: 1 }}
315	                exit={{ opacity: 0 }}
316	                transition={{ duration: 0.15 }}
317	                className="h-full overflow-y-auto"
318	              >
319	                <div className="p-6 max-w-lg mx-auto">
320	                  <div className="flex items-center gap-2 mb-5">
321	                    <Users className="w-4 h-4 text-bronze/70" />
322	                    <h2 className="text-sm font-semibold text-foreground/80 tracking-tight">
323	                      Workspace Members
324	                    </h2>
325	                  </div>
326	
327	                  {loadingMembers ? (
328	                    <div className="flex justify-center py-12">
329	                      <Loader2 className="w-5 h-5 animate-spin text-muted-foreground/40" />
330	                    </div>
331	                  ) : workspaceMembers.length === 0 ? (
332	                    <div className="text-center py-12">
333	                      <div className="w-14 h-14 rounded-2xl bg-muted/60 flex items-center justify-center mx-auto mb-3">
334	                        <Users className="w-6 h-6 text-muted-foreground/30" />
335	                      </div>
336	                      <p className="text-sm font-medium text-foreground/60 mb-1">
337	                        No other members yet
338	                      </p>
339	                      <p className="text-xs text-muted-foreground/50">
340	                        Invite someone via the Propose Workspace button in a DM.
341	                      </p>
342	                    </div>
343	                  ) : (
344	                    <div className="space-y-2">
345	                      {workspaceMembers.map((member) => {
346	                        const name =
347	                          member.profile?.display_name ||
348	                          (member.profile?.handle
349	                            ? `@${member.profile.handle}`
350	                            : "Unknown");
351	                        const initial = name[0].toUpperCase();
352	                        const isOpening = openingDm === member.user_id;
353	
354	                        return (
355	                          <div
356	                            key={member.user_id}
357	                            className="flex items-center gap-3 p-3 rounded-xl border border-gray-100 dark:border-border/40 bg-card hover:border-bronze/25 hover:shadow-sm transition-all duration-200"
358	                          >
359	                            <div className="w-10 h-10 rounded-full bg-bronze/10 flex items-center justify-center overflow-hidden flex-shrink-0">
360	                              {member.profile?.avatar_url ? (
361	                                <img
362	                                  src={member.profile.avatar_url}
363	                                  alt={name}
364	                                  className="w-full h-full object-cover"
365	                                />
366	                              ) : (
367	                                <span className="text-sm font-bold text-bronze/70">
368	                                  {initial}
369	                                </span>
370	                              )}
371	                            </div>
372	                            <div className="min-w-0 flex-1">
373	                              <p className="text-sm font-medium truncate">{name}</p>
374	                              <div className="flex items-center gap-1.5">
375	                                {member.profile?.handle && (
376	                                  <p className="text-xs text-muted-foreground truncate">
377	                                    @{member.profile.handle}
378	                                  </p>
379	                                )}
380	                                {member.role === "admin" && (
381	                                  <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-bronze/10 text-bronze font-semibold">
382	                                    admin
383	                                  </span>
384	                                )}
385	                              </div>
386	                            </div>
387	                            <Button
388	                              size="sm"
389	                              variant="outline"
390	                              onClick={() =>
391	                                openDmWithMember(member.user_id, name)
392	                              }
393	                              disabled={isOpening}
394	                              className="flex-shrink-0 h-8 text-xs gap-1.5 border-bronze/25 text-bronze hover:bg-bronze/8 hover:border-bronze/50 font-medium"
395	                            >
396	                              {isOpening ? (
397	                                <Loader2 className="w-3 h-3 animate-spin" />
398	                              ) : (
399	                                <MessageCircle className="w-3 h-3" />
400	                              )}
401	                              Chat
402	                            </Button>
403	                          </div>
404	                        );
405	                      })}
406	                    </div>
407	                  )}
408	                </div>
409	              </motion.div>
410	            ) : (
411	              /* No room selected */
412	              <motion.div
413	                key="empty"
414	                initial={{ opacity: 0 }}
415	                animate={{ opacity: 1 }}
416	                className="h-full flex flex-col items-center justify-center text-center p-8"
417	              >
418	                <div className="w-16 h-16 rounded-2xl bg-bronze/8 dark:bg-bronze/10 flex items-center justify-center mb-4">
419	                  <MessageSquare className="w-7 h-7 text-bronze/40" />
420	                </div>
421	                <h3 className="font-semibold text-sm mb-1.5 tracking-tight">
422	                  Select a conversation
423	                </h3>
424	                <p className="text-[12px] text-muted-foreground max-w-[240px] leading-relaxed">
425	                  Choose a deal room or message from the list to open the
426	                  collaboration thread.
427	                </p>
428	              </motion.div>
429	            )}
430	          </AnimatePresence>
431	        </div>
432	      </div>
433	
434	      {/* Propose Workspace Dialog */}
435	      <Dialog
436	        open={proposeDialogOpen}
437	        onOpenChange={(o) => {
438	          if (!o) setProposeDialogOpen(false);
439	        }}
440	      >
441	        <DialogContent className="max-w-sm">
442	          <DialogHeader>
443	            <div className="flex items-center gap-2 mb-1">
444	              <div className="p-1.5 rounded-lg bg-bronze/10">
445	                <Sparkles className="w-4 h-4 text-bronze" />
446	              </div>
